import React, { useState, useEffect } from 'react';
import { Users, Trophy, Clock, Play, Search, Filter, Gift, Zap } from 'lucide-react';

interface Tournament {
  _id: string;
  name: string;
  description: string;
  participants: number;
  maxParticipants: number;
  startDate: string;
  endDate: string;
  prize: string;
  points: number;
  difficulty: 'Beginner' | 'Intermediate' | 'Advanced' | 'Expert';
  status: 'upcoming' | 'active' | 'completed';
}

interface LeaderboardEntry {
  _id: string;
  rank: number;
  username: string;
  score: number;
  scenariosCompleted: number;
  points: number;
  countryCode: string;
}

interface Friend {
  _id: string;
  username: string;
  status: 'online' | 'away' | 'offline';
  lastActive: string;
  score: number;
  points: number;
}

const Multiplayer: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'tournaments' | 'leaderboard' | 'friends' | 'rules'>('tournaments');
  const [searchTerm, setSearchTerm] = useState('');
  const [tournaments, setTournaments] = useState<Tournament[]>([]);
  const [leaderboard, setLeaderboard] = useState<LeaderboardEntry[]>([]);
  const [friends, setFriends] = useState<Friend[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Fetch data from backend
  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        
        // In a real implementation, we would fetch data from the backend
        // For now, we'll use mock data but simulate an API call
        await new Promise(resolve => setTimeout(resolve, 1000));
        
        // Mock data (will be replaced with real data from backend)
        const mockTournaments: Tournament[] = [
          {
            _id: "1",
            name: "Criminal Law Championship",
            description: "Compete in complex criminal law scenarios with real-world cases",
            participants: 42,
            maxParticipants: 100,
            startDate: new Date(2025, 10, 15).toISOString(),
            endDate: new Date(2025, 10, 22).toISOString(),
            prize: "₹25,000 + Certificate",
            points: 5000,
            difficulty: "Advanced",
            status: "active"
          },
          {
            _id: "2",
            name: "Contract Drafting Tournament",
            description: "Showcase your contract drafting skills in timed challenges",
            participants: 78,
            maxParticipants: 150,
            startDate: new Date(2025, 10, 20).toISOString(),
            endDate: new Date(2025, 10, 27).toISOString(),
            prize: "₹15,000 + Certificate",
            points: 3000,
            difficulty: "Intermediate",
            status: "upcoming"
          },
          {
            _id: "3",
            name: "Family Law Masters",
            description: "Navigate complex family law scenarios with sensitivity and expertise",
            participants: 25,
            maxParticipants: 50,
            startDate: new Date(2025, 9, 1).toISOString(),
            endDate: new Date(2025, 9, 8).toISOString(),
            prize: "₹30,000 + Certificate",
            points: 7000,
            difficulty: "Expert",
            status: "completed"
          }
        ];

        const mockLeaderboard: LeaderboardEntry[] = [
          { _id: "1", rank: 1, username: "Aditi Sharma", score: 98, scenariosCompleted: 142, points: 12500, countryCode: "IN" },
          { _id: "2", rank: 2, username: "Raj Patel", score: 96, scenariosCompleted: 138, points: 10000, countryCode: "IN" },
          { _id: "3", rank: 3, username: "Priya Kumar", score: 94, scenariosCompleted: 135, points: 8500, countryCode: "IN" },
          { _id: "4", rank: 4, username: "Michael Chen", score: 92, scenariosCompleted: 129, points: 7000, countryCode: "SG" },
          { _id: "5", rank: 5, username: "Sarah Johnson", score: 90, scenariosCompleted: 127, points: 6000, countryCode: "US" },
          { _id: "6", rank: 6, username: "James Wilson", score: 88, scenariosCompleted: 124, points: 5000, countryCode: "GB" },
          { _id: "7", rank: 7, username: "You", score: 85, scenariosCompleted: 118, points: 4500, countryCode: "IN" },
          { _id: "8", rank: 8, username: "Nikhil Reddy", score: 84, scenariosCompleted: 115, points: 4000, countryCode: "IN" },
          { _id: "9", rank: 9, username: "Emma Thompson", score: 82, scenariosCompleted: 112, points: 3500, countryCode: "AU" },
          { _id: "10", rank: 10, username: "David Kim", score: 80, scenariosCompleted: 109, points: 3000, countryCode: "KR" }
        ];

        const mockFriends: Friend[] = [
          { _id: "1", username: "Amit Verma", status: "online", lastActive: "Active now", score: 82, points: 4200 },
          { _id: "2", username: "Sneha Gupta", status: "online", lastActive: "Active now", score: 78, points: 3800 },
          { _id: "3", username: "Rohan Mehta", status: "away", lastActive: "2 hours ago", score: 85, points: 5100 },
          { _id: "4", username: "Pooja Singh", status: "offline", lastActive: "5 hours ago", score: 76, points: 3500 },
          { _id: "5", username: "Karan Desai", status: "online", lastActive: "Active now", score: 88, points: 6200 }
        ];

        setTournaments(mockTournaments);
        setLeaderboard(mockLeaderboard);
        setFriends(mockFriends);
        
        setLoading(false);
      } catch (err) {
        setError('Error fetching multiplayer data: ' + (err as Error).message);
        console.error('Error fetching multiplayer data:', err);
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'active': return 'bg-green-100 text-green-800';
      case 'upcoming': return 'bg-blue-100 text-blue-800';
      case 'completed': return 'bg-gray-100 text-gray-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getDifficultyColor = (difficulty: string) => {
    switch (difficulty) {
      case 'Beginner': return 'bg-green-100 text-green-800';
      case 'Intermediate': return 'bg-blue-100 text-blue-800';
      case 'Advanced': return 'bg-yellow-100 text-yellow-800';
      case 'Expert': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'online': return <div className="w-3 h-3 rounded-full bg-green-500"></div>;
      case 'away': return <div className="w-3 h-3 rounded-full bg-yellow-500"></div>;
      case 'offline': return <div className="w-3 h-3 rounded-full bg-gray-500"></div>;
      default: return <div className="w-3 h-3 rounded-full bg-gray-500"></div>;
    }
  };

  const filteredTournaments = tournaments.filter(tournament => 
    tournament.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    tournament.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-12">
        <div className="text-center">
          <div className="inline-block animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
          <p className="text-gray-600">Loading multiplayer data...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container mx-auto px-4 py-12">
        <div className="text-center py-12">
          <div className="bg-red-100 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4">
            <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>
            </svg>
          </div>
          <h3 className="text-xl font-bold text-gray-900 mb-2">Error Loading Multiplayer Data</h3>
          <p className="text-gray-600 mb-4">{error}</p>
          <button 
            className="bg-indigo-600 text-white px-6 py-3 rounded-lg hover:bg-indigo-700 transition duration-300 font-medium"
            onClick={() => window.location.reload()}
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900">Multiplayer Mode</h1>
        <p className="text-gray-600">Compete with peers and climb the leaderboards to earn bonus points</p>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-gray-200 mb-8">
        <button
          className={`pb-3 px-6 font-medium ${activeTab === 'tournaments' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
          onClick={() => setActiveTab('tournaments')}
        >
          <Trophy className="w-5 h-5 inline mr-2" />
          Tournaments
        </button>
        <button
          className={`pb-3 px-6 font-medium ${activeTab === 'leaderboard' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
          onClick={() => setActiveTab('leaderboard')}
        >
          <Users className="w-5 h-5 inline mr-2" />
          Leaderboard
        </button>
        <button
          className={`pb-3 px-6 font-medium ${activeTab === 'friends' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
          onClick={() => setActiveTab('friends')}
        >
          <Users className="w-5 h-5 inline mr-2" />
          Friends
        </button>
        <button
          className={`pb-3 px-6 font-medium ${activeTab === 'rules' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
          onClick={() => setActiveTab('rules')}
        >
          <svg className="w-5 h-5 inline mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path>
          </svg>
          Rules & Points
        </button>
      </div>

      {/* Tournaments Tab */}
      {activeTab === 'tournaments' && (
        <div>
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
            <h2 className="text-2xl font-bold text-gray-900">Active Tournaments</h2>
            <div className="flex gap-3 w-full md:w-auto">
              <div className="relative flex-1 md:flex-none">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
                <input
                  type="text"
                  placeholder="Search tournaments..."
                  className="pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent w-full"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
              <button className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition duration-300 flex items-center">
                <Filter className="w-5 h-5 mr-2" />
                Filter
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {filteredTournaments.map(tournament => (
              <div key={tournament._id} className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <h3 className="text-xl font-bold text-gray-900 mb-2">{tournament.name}</h3>
                    <span className={`inline-block px-3 py-1 rounded-full text-xs font-medium ${getStatusColor(tournament.status)} mr-2`}>
                      {tournament.status.charAt(0).toUpperCase() + tournament.status.slice(1)}
                    </span>
                    <span className={`inline-block px-3 py-1 rounded-full text-xs font-medium ${getDifficultyColor(tournament.difficulty)}`}>
                      {tournament.difficulty}
                    </span>
                  </div>
                  <div className="bg-indigo-100 text-indigo-800 px-3 py-1 rounded-lg font-medium flex items-center">
                    <Gift className="w-4 h-4 mr-1" />
                    {tournament.points} pts
                  </div>
                </div>
                
                <p className="text-gray-600 mb-6">{tournament.description}</p>
                
                <div className="grid grid-cols-2 gap-4 mb-6">
                  <div className="bg-gray-50 rounded-lg p-4">
                    <div className="flex items-center text-gray-500 mb-1">
                      <Users className="w-4 h-4 mr-2" />
                      <span className="text-sm">Participants</span>
                    </div>
                    <div className="text-lg font-bold text-gray-900">
                      {tournament.participants}/{tournament.maxParticipants}
                    </div>
                  </div>
                  
                  <div className="bg-gray-50 rounded-lg p-4">
                    <div className="flex items-center text-gray-500 mb-1">
                      <Clock className="w-4 h-4 mr-2" />
                      <span className="text-sm">Duration</span>
                    </div>
                    <div className="text-lg font-bold text-gray-900">
                      {Math.ceil((new Date(tournament.endDate).getTime() - new Date(tournament.startDate).getTime()) / (1000 * 60 * 60 * 24))} days
                    </div>
                  </div>
                </div>
                
                <div className="flex justify-between items-center">
                  <div className="text-sm text-gray-500">
                    Starts: {new Date(tournament.startDate).toLocaleDateString()}
                  </div>
                  <button className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition duration-300 flex items-center">
                    <Play className="w-5 h-5 mr-2" />
                    Join Tournament
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Leaderboard Tab */}
      {activeTab === 'leaderboard' && (
        <div>
          <h2 className="text-2xl font-bold text-gray-900 mb-6">Global Leaderboard</h2>
          
          <div className="bg-white rounded-xl shadow-sm overflow-hidden border border-gray-100 mb-8">
            <div className="grid grid-cols-12 gap-4 px-6 py-4 bg-gray-50 border-b border-gray-200 font-medium text-gray-700">
              <div className="col-span-1">Rank</div>
              <div className="col-span-4">Player</div>
              <div className="col-span-3">Scenarios</div>
              <div className="col-span-2">Score</div>
              <div className="col-span-2 text-right">Points</div>
            </div>
            
            <div className="divide-y divide-gray-100">
              {leaderboard.map(player => (
                <div 
                  key={player._id} 
                  className={`grid grid-cols-12 gap-4 px-6 py-4 ${player.username === 'You' ? 'bg-indigo-50' : 'hover:bg-gray-50'}`}
                >
                  <div className="col-span-1 flex items-center">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold ${player.rank <= 3 ? 'text-white' : 'text-gray-700'} ${player.rank === 1 ? 'bg-yellow-500' : player.rank === 2 ? 'bg-gray-400' : player.rank === 3 ? 'bg-amber-700' : 'bg-gray-200'}`}>
                      {player.rank}
                    </div>
                  </div>
                  <div className="col-span-4 flex items-center">
                    <div className="flex items-center">
                      <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center mr-3 font-bold text-indigo-800">
                        {player.username.charAt(0)}
                      </div>
                      <div>
                        <div className="font-medium text-gray-900">{player.username}</div>
                        <div className="text-sm text-gray-500 flex items-center">
                          <span className="mr-2">{player.countryCode}</span>
                        </div>
                      </div>
                    </div>
                  </div>
                  <div className="col-span-3 flex items-center text-gray-700">
                    {player.scenariosCompleted}
                  </div>
                  <div className="col-span-2 flex items-center font-bold text-gray-900">
                    {player.score}
                  </div>
                  <div className="col-span-2 flex items-center justify-end font-bold text-indigo-600">
                    {player.points.toLocaleString()}
                  </div>
                </div>
              ))}
            </div>
          </div>
          
          <div className="bg-gradient-to-r from-indigo-500 to-purple-600 rounded-2xl p-8 text-white">
            <div className="max-w-3xl mx-auto text-center">
              <div className="flex justify-center mb-4">
                <div className="w-16 h-16 bg-white bg-opacity-20 rounded-full flex items-center justify-center">
                  <Gift className="w-8 h-8" />
                </div>
              </div>
              <h3 className="text-2xl font-bold mb-4">Earn Bonus Points in Tournaments</h3>
              <p className="text-indigo-100 mb-6">
                Participate in multiplayer tournaments and climb the leaderboard to earn bonus points that can be used to unlock premium scenarios in the marketplace.
              </p>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                <div className="bg-white bg-opacity-10 rounded-lg p-4">
                  <div className="text-2xl font-bold mb-2">1st Place</div>
                  <div className="text-indigo-200">5,000 points</div>
                </div>
                <div className="bg-white bg-opacity-10 rounded-lg p-4">
                  <div className="text-2xl font-bold mb-2">2nd Place</div>
                  <div className="text-indigo-200">3,000 points</div>
                </div>
                <div className="bg-white bg-opacity-10 rounded-lg p-4">
                  <div className="text-2xl font-bold mb-2">3rd Place</div>
                  <div className="text-indigo-200">2,000 points</div>
                </div>
              </div>
              <button className="bg-white text-indigo-600 px-6 py-3 rounded-lg hover:bg-indigo-50 transition duration-300 font-medium">
                View Tournaments
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Friends Tab */}
      {activeTab === 'friends' && (
        <div>
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-2xl font-bold text-gray-900">Friends</h2>
            <button className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition duration-300">
              Add Friends
            </button>
          </div>
          
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {friends.map(friend => (
              <div key={friend._id} className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
                <div className="flex items-center mb-4">
                  <div className="w-12 h-12 rounded-full bg-indigo-100 flex items-center justify-center mr-4 font-bold text-indigo-800">
                    {friend.username.charAt(0)}
                  </div>
                  <div className="flex-1">
                    <h3 className="font-bold text-gray-900">{friend.username}</h3>
                    <div className="flex items-center">
                      {getStatusIcon(friend.status)}
                      <span className="text-sm text-gray-500 ml-2">{friend.lastActive}</span>
                    </div>
                  </div>
                </div>
                
                <div className="grid grid-cols-2 gap-3 mb-4">
                  <div className="bg-gray-50 rounded-lg p-3 text-center">
                    <div className="text-sm text-gray-500 mb-1">Score</div>
                    <div className="font-bold text-gray-900">{friend.score}</div>
                  </div>
                  <div className="bg-indigo-50 rounded-lg p-3 text-center">
                    <div className="text-sm text-indigo-500 mb-1">Points</div>
                    <div className="font-bold text-indigo-600">{friend.points.toLocaleString()}</div>
                  </div>
                </div>
                
                <div className="flex gap-3">
                  <button className="flex-1 bg-indigo-600 text-white py-2 rounded-lg hover:bg-indigo-700 transition duration-300 text-sm">
                    Challenge
                  </button>
                  <button className="flex-1 bg-white border border-gray-300 text-gray-700 py-2 rounded-lg hover:bg-gray-50 transition duration-300 text-sm">
                    Message
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Rules & Points Tab */}
      {activeTab === 'rules' && (
        <div>
          <h2 className="text-2xl font-bold text-gray-900 mb-6">Rules & Points System</h2>
          
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Points System Guide */}
            <div className="lg:col-span-2">
              <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100 mb-8">
                <h3 className="text-xl font-bold text-gray-900 mb-4">How Points Work</h3>
                <p className="text-gray-600 mb-6">
                  Earn bonus points through multiplayer tournaments and use them to unlock premium scenarios in the marketplace.
                </p>
                
                <div className="space-y-6">
                  <div className="flex items-start">
                    <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center mr-4 flex-shrink-0">
                      <span className="text-indigo-600 font-bold">1</span>
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-900 mb-2">Earn Points in Tournaments</h4>
                      <p className="text-gray-600">
                        Participate in multiplayer tournaments to earn bonus points based on your ranking. 
                        Higher rankings earn more points.
                      </p>
                    </div>
                  </div>
                  
                  <div className="flex items-start">
                    <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center mr-4 flex-shrink-0">
                      <span className="text-indigo-600 font-bold">2</span>
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-900 mb-2">Use Points in Marketplace</h4>
                      <p className="text-gray-600">
                        Spend your earned points to unlock premium scenarios in the marketplace. 
                        Each scenario has a point cost displayed.
                      </p>
                    </div>
                  </div>
                  
                  <div className="flex items-start">
                    <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center mr-4 flex-shrink-0">
                      <span className="text-indigo-600 font-bold">3</span>
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-900 mb-2">Subscription Bonuses</h4>
                      <p className="text-gray-600">
                        Subscribers receive bonus points with their plan and discounts on scenario purchases.
                      </p>
                    </div>
                  </div>
                </div>
              </div>
              
              <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
                <h3 className="text-xl font-bold text-gray-900 mb-4">Tournament Rules</h3>
                
                <div className="space-y-6">
                  <div>
                    <h4 className="font-bold text-gray-900 mb-2">Participation Requirements</h4>
                    <ul className="list-disc pl-5 space-y-2 text-gray-600">
                      <li>Must have completed at least 5 scenarios in the platform</li>
                      <li>Participants must join before the tournament start time</li>
                      <li>Only one account per person is allowed</li>
                    </ul>
                  </div>
                  
                  <div>
                    <h4 className="font-bold text-gray-900 mb-2">Competition Format</h4>
                    <ul className="list-disc pl-5 space-y-2 text-gray-600">
                      <li>Each tournament consists of 3-5 legal scenarios</li>
                      <li>Participants have a fixed time limit for each scenario</li>
                      <li>Scoring is based on accuracy, speed, and argument quality</li>
                      <li>Final ranking is determined by cumulative score</li>
                    </ul>
                  </div>
                  
                  <div>
                    <h4 className="font-bold text-gray-900 mb-2">Fair Play Policy</h4>
                    <ul className="list-disc pl-5 space-y-2 text-gray-600">
                      <li>No external assistance or collaboration during tournaments</li>
                      <li>Use of automated tools or scripts is prohibited</li>
                      <li>Violations may result in disqualification and account suspension</li>
                    </ul>
                  </div>
                </div>
              </div>
            </div>
            
            {/* Points Rewards */}
            <div>
              <div className="bg-gradient-to-br from-indigo-500 to-purple-600 rounded-2xl p-6 text-white mb-8">
                <h3 className="text-xl font-bold mb-4">Tournament Rewards</h3>
                <div className="space-y-4">
                  <div className="flex justify-between items-center p-3 bg-white bg-opacity-20 rounded-lg">
                    <span>1st Place</span>
                    <span className="font-bold">5,000 points</span>
                  </div>
                  <div className="flex justify-between items-center p-3 bg-white bg-opacity-20 rounded-lg">
                    <span>2nd Place</span>
                    <span className="font-bold">3,000 points</span>
                  </div>
                  <div className="flex justify-between items-center p-3 bg-white bg-opacity-20 rounded-lg">
                    <span>3rd Place</span>
                    <span className="font-bold">2,000 points</span>
                  </div>
                  <div className="flex justify-between items-center p-3 bg-white bg-opacity-20 rounded-lg">
                    <span>4th-10th Place</span>
                    <span className="font-bold">1,000 points</span>
                  </div>
                  <div className="flex justify-between items-center p-3 bg-white bg-opacity-20 rounded-lg">
                    <span>Top 25%</span>
                    <span className="font-bold">500 points</span>
                  </div>
                </div>
              </div>
              
              <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
                <h3 className="text-xl font-bold text-gray-900 mb-4">Points Value</h3>
                <div className="space-y-4">
                  <div className="flex justify-between">
                    <span className="text-gray-600">100 points =</span>
                    <span className="font-medium">₹10 value</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-600">500 points =</span>
                    <span className="font-medium">₹50 value</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-600">1,000 points =</span>
                    <span className="font-medium">₹100 value</span>
                  </div>
                  <div className="pt-4 border-t border-gray-200">
                    <p className="text-sm text-gray-500">
                      Points can be used for scenario purchases and subscription discounts
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Multiplayer;
